import type { DialogueEntry } from '../../../types';
import { CharacterId } from '../../../characters';

export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "雨停了，但天空沒有放晴。雲層壓得很低，灰白色的，像一塊洗了太多次的舊布，透不出光也掉不下水。空氣裡全是濕氣，吸進肺裡涼涼的，帶著泥土和瀝青混合的味道。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "校門口搭了一排臨時帳篷，藍白相間的帆布被風吹得微微鼓起。帳篷下面是安全檢查區，幾個穿著反光背心的保安站在金屬探測門兩側，臉上的表情既疲憊又警惕，像站了一整個早上。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "來訪的人比預計的多。家長、校友、媒體記者、供應商，各種各樣的人在帳篷下排隊等候安檢，隊伍從校門口一直延伸到人行道上，拐了個彎，消失在街角。有人在低頭看手機，有人在打電話，有人在抱怨停車位太少。嘈雜聲混在一起，像一鍋煮開了的粥。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)十一點。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他站在校門內側的主道上，背靠著一棵行道樹，雙手插在口袋裡。口袋右邊是手機，左邊是一團揉皺的衛生紙。他已經在這裡站了快二十分鐘，沒有目的地，只是不想回宿舍，也不想再去校史館。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)搬完箱子也沒什麼事做了。下午的志工排班要到兩點。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他正準備往教學樓方向走，餘光看到一輛深藍色的警用巡邏車從校門外緩緩駛入。車速不快，像是刻意在巡視，車頂的警示燈沒有開，但車身側面的「鳴海分局」四個白字在灰天底下格外顯眼。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "車停在臨時指揮室旁邊。指揮室是用活動板房搭的，門口掛著「校慶安保臨時指揮中心」的牌子，旁邊還有一面小旗，被風吹得啪啪響。一個穿制服的警員從板房裡走出來，朝巡邏車的方向小跑了幾步。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "車門打開。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "下來的人穿著合身的深藍色制服，肩上的警銜在灰暗的天色裡反射出一點微光。他個子不算高，皮膚偏黑，頭髮剪得很短，貼著頭皮的弧度像剛用電推刀修過。走路的方式很穩，腳步不急不慢，但每一步都踩得很實，像一個習慣了在地面尋找重心的人。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)邵叔。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "邵啟明。鳴海分局的基層警員，今年四十出頭，在分局幹了快二十年。他不是什麼大人物，沒有警銜上的星，沒有報導裡的功勞，只是一個在社區巡邏了半輩子的普通警察。但對顧言來說，他是這個鎮上少數幾個不會用異樣眼光看他的人之一。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "邵叔和從指揮室出來的警員說了幾句話，語速不快，一邊說一邊點頭。那個警員看上去很年輕，對邵叔的態度帶著一種下級對上級的恭敬，雖然肩章上他們的級別差不多。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "說完之後，邵叔朝校門內的方向看了一眼。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後他看見了顧言。" },
    { characterId: CharacterId.ShaoQiming, character: "邵叔", dialogue: "小顧？" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他的聲音不大，但穿透力很強，帶著一種中年男人特有的渾厚，像敲了一下木魚。他朝顧言走了過來，步伐沒有加快，但路線很直，像一開始就知道要往哪裡走。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)⋯⋯被發現了。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他沒有躲，也沒有迎上去，只是站在原地，把手從口袋裡抽出來。" },
    { characterId: CharacterId.ShaoQiming, character: "邵叔", dialogue: "怎麼一個人在這裡？吃飯了沒有？" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "邵叔走到他面前的時候，很自然地拍了拍他的肩膀。力道不重，手掌落在肩胛骨上方的位置，帶著一種不需要語言的熟悉感。這個動作他做過很多次了，從顧言還不到他腰高的時候就開始了。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "吃了。" },
    { characterId: CharacterId.ShaoQiming, character: "邵叔", dialogue: "吃了什麼？" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "⋯⋯飯。" },
    { characterId: CharacterId.ShaoQiming, character: "邵叔", dialogue: "飯。白飯？" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "食堂的炒飯。" },
    { characterId: CharacterId.ShaoQiming, character: "邵叔", dialogue: "一大早吃炒飯，你胃受得了嗎？" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)關心過度了。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "受得了。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "邵叔看了他一眼，那種看法不是審視，也不是同情，更像是一個已經習慣了檢查零件的老技工，掃一眼就知道哪裡鬆了、哪裡緊了。然後他笑了一下，露出一排整齊的白牙，嘴角兩側的法令紋跟著加深，整張臉看起來放鬆而自然。" },
    { characterId: CharacterId.ShaoQiming, character: "邵叔", dialogue: "你啊，跟小時候一樣，問一句答一個字。多一個標點符號都不肯給。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)小時候。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言的目光動了一下。他想起了那張照片——照片裡的邵叔也是這個笑容，露出一口白牙，手裡拿著扳手，站在他父親旁邊。那是十幾年前了，邵叔比現在瘦很多，但笑起來的樣子一點都沒變。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "邵叔今天怎麼來了？" },
    { characterId: CharacterId.ShaoQiming, character: "邵叔", dialogue: "局裡安排的，今天是校慶，人流量大，分局派了幾個人過來協助安保。我被分到這裡當聯絡官，對接校方和指揮中心。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他說這話的時候，語氣很平常，像在陳述一個事實。但他順手指了指身後的臨時指揮室，那個動作帶著一種不經意的權威——這裡是我的地盤，我在這裡有角色。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)聯絡官。所以邵叔可以進出指揮室，可以看所有的監控畫面，可以知道所有的安保佈置。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)不過這也很正常。他是警察，本來就是做這個的。" },
    { characterId: CharacterId.ShaoQiming, character: "邵叔", dialogue: "你今天在學校幫忙？志工？" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "嗯。校史館搬東西。" },
    { characterId: CharacterId.ShaoQiming, character: "邵叔", dialogue: "辛苦了。中午有沒有休息的地方？今天冷，別在外頭站太久。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "我知道。" },
    { characterId: CharacterId.ShaoQiming, character: "邵叔", dialogue: "你那件外套太薄了，早上不是還下了雨？穿厚一點。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)又來了。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "不冷。" },
    { characterId: CharacterId.ShaoQiming, character: "邵叔", dialogue: "十七歲的人覺得不冷，四十七歲的膝蓋第一個不同意。你以後就知道了。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他說完這句話的時候自己先笑了，笑聲很輕，從鼻子裡哼出來的，像一個人對自己講了個不太好笑的笑話但還是決定笑一下。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言沒有笑，但他的肩膀微微鬆了一點。他自己可能沒有意識到，但在邵叔面前，他的站姿沒有在其他成年人面前那麼僵。不是放鬆，只是沒有那麼緊繃。像一根被拉得太緊的弦，有人按了一下，沒有放鬆，但至少給了一個緩衝的弧度。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "安檢區那邊傳來一陣小騷動，有個家長的包裡被查出來帶了一把水果刀，保安正在解釋規定。邵叔回頭看了一眼，判斷了一下不是什麼大事，又轉回來。" },
    { characterId: CharacterId.ShaoQiming, character: "邵叔", dialogue: "對了，你爸那個案子——" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)不要說。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言的表情幾乎是瞬間冷的。不是憤怒，是那種像門被摔上的冷——快速、堅決、沒有商量的餘地。他的眼神從邵叔的臉上移開，落在遠處的鐘樓方向，然後停在那裡不動了。" },
    { characterId: CharacterId.ShaoQiming, character: "邵叔", dialogue: "⋯⋯算了，不提了。今天不說這個。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "邵叔的反應很快，他像是讀到了什麼信號一樣，及時把話收了回去。他沒有追問，沒有解釋，沒有用那種「我是為了你好」的語氣繼續說下去。他只是頓了一下，然後把話題斷掉，像剪斷一根多餘的線頭。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這也是顧言不排斥邵叔的原因之一。他會停。大部分成年人不會停。他們問完一個問題，不管你的反應是什麼，他們都會繼續往下說，用各種各樣的方式把話塞進你耳朵裡——關心的、勸導的、教育的、評判的。但邵叔會停。他問了，你不想答，他就不再問。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)⋯⋯謝謝。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)不是真的想說謝謝，但心裡有這個感覺。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "沉默了大約五六秒。五六秒在對話裡是一段很長的空白，長到旁邊經過的學生都看了他們一眼。但邵叔沒有尷尬，他只是站著，雙手背在身後，看著安檢區的方向，像一個在等人的人，一點都不著急。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後顧言做了一件連他自己都沒有預料到的事。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他把右手從口袋裡抽出來，拿出手機，解鎖，找到那條訊息，把手機遞給了邵叔。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "邵叔，你看這個。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "邵叔微微側身，接過手機。他的手指很粗，指腹有老繭，按螢幕的時候動作比年輕人慢半拍，但很穩。他眯著眼看了幾秒。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "螢幕上是那條匿名訊息。沒有發送者號碼，沒有頭像，只有一串簡潔到近乎冷酷的文字：" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "「22:22。鐘樓。相機。你欠自己一個真相。」" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)為什麼給他看？" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)不知道。大概是因為他是邵叔。如果是別人，我不會。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "邵叔讀得很慢。他的眉毛先是平的，然後微微皺了一下，皺紋集中在眉心，像兩條短的平行線。他的嘴唇動了一下，像在無聲地把那幾個字重複一遍。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後他的表情變了。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "很短。短到如果顧言在眨眼，就會錯過。那不是驚訝、不是困惑、不是擔心，而是一種更深層的東西——像是一個人在名單裡看到了自己不應該出現的名字，臉上的肌肉還沒來得及調整，就被大腦緊急覆蓋了一層其他的表情。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "那個瞬間持續了不到一秒。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後邵叔的臉恢復了。恢復得很快、很自然，像水面被石子砸了一下又立刻變平。他又變成了那個溫和的、可靠的、微微發胖的中年警察，用一種「見過大場面」的平靜語氣開了口。" },
    { characterId: CharacterId.ShaoQiming, character: "邵叔", dialogue: "可能是哪個學生惡作劇。今天人多，你別亂跑。這件事交給我。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)惡作劇。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)他說是惡作劇。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)⋯⋯大概是吧。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "邵叔把手機還給他，動作很自然，但顧言注意到他還回去的時候，手指在螢幕上多停留了一瞬。不是在滑動，也不是在按什麼，只是停了一下，像是在確認什麼東西已經看完了。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他的目光最後停留的位置是「相機」兩個字。那個停頓很短，可能只有零點幾秒，短到顧言根本沒有注意到——他的注意力在那個瞬間正在想別的事。他在想邵叔說「這件事交給我」的時候，語氣裡有沒有別的意思。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)交給他。好吧。他是警察，處理這種事本來就是他的工作。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)比起告訴學校老師，告訴邵叔更好。至少他不會用那種眼神看我。" },
    { characterId: CharacterId.ShaoQiming, character: "邵叔", dialogue: "這種匿名訊息，有時候就是有人閒著沒事幹，故意寫點嚇人的東西。鐘樓、相機、什麼真相——聽起來像推理小說的開頭，對吧？" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "嗯。" },
    { characterId: CharacterId.ShaoQiming, character: "邵叔", dialogue: "你晚上不要去鐘樓。那邊本來就不開放，今天是校慶，更不應該有學生跑到那裡去。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "我知道。" },
    { characterId: CharacterId.ShaoQiming, character: "邵叔", dialogue: "知道就好。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "邵叔頓了一下，像是在考慮要不要說下一句話。他的嘴唇抿了一下，又鬆開，然後他用一種很隨意的、像是隨口問問的語氣開了口。" },
    { characterId: CharacterId.ShaoQiming, character: "邵叔", dialogue: "你最近有沒有想起小時候的事？" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "空氣裡有什麼東西變了。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是溫度，不是風，不是雨後的濕氣。是更細微的東西——像是房間裡本來開著的燈被調暗了一格，差別很小，但你就是覺得光線不一樣了。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)⋯⋯什麼意思？" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "沒有。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他的回答很快。快到幾乎是搶答，像是在邵叔的問題落完之前就把門關上了。他的語氣是平的，但平得過分，像一面剛刷過漆的牆，什麼都看不見。" },
    { characterId: CharacterId.ShaoQiming, character: "邵叔", dialogue: "沒有就想不起來了唄。你那時候才幾歲，三歲？四歲？記不住很正常。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "嗯。" },
    { characterId: CharacterId.ShaoQiming, character: "邵叔", dialogue: "小孩子的事，忘就忘了。沒什麼重要的。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)他在說「沒什麼重要的」。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)可是他問了。他主動問的。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)如果他覺得不重要，為什麼要問？" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)⋯⋯算了。他大概只是隨口聊聊。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "邵叔沒有再追問。他像剛才一樣，問完了，得不到想要的回答，就收回去，不逼、不勸、不解釋。這讓顧言感到安全，同時也讓他隱隱覺得不安——這種安全感太舒服了，舒服到不像真的。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但他沒有細想這個念頭。他十七歲，他累了，他不想分析每一個對他好的人的動機。有些東西看起來是好的，那就先當它是好的。至少今天先這樣。" },
    { characterId: CharacterId.ShaoQiming, character: "邵叔", dialogue: "好了，你先回去吧。中午記得吃飽一點，下午還要忙。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "嗯。" },
    { characterId: CharacterId.ShaoQiming, character: "邵叔", dialogue: "有什麼事打我電話。你知道我的號碼。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "我知道。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "邵叔又拍了拍他的肩膀。這一次比第一次輕，更像是確認——確認你還在，確認你還站得住，確認你沒有碎。然後他轉過身，朝臨時指揮室的方向走去。走了幾步，他又停了一下，回過頭。" },
    { characterId: CharacterId.ShaoQiming, character: "邵叔", dialogue: "對了，你那件外套，回去換一件厚的。聽話。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)⋯⋯知道了。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他沒有說出口。他只是點了點頭，動作很小，下巴往下動了一下就收回來了。但邵叔看到了，笑了一下，轉身走了。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "邵叔的背影消失在指揮室的門口。他推門進去的時候，裡面有幾個穿制服的人在走動，桌上的對講機正在發出斷斷續續的沙沙聲。門在他身後關上，金屬門框撞擊的聲音很沉，悶悶的，像敲在一個空箱子上。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言站在原地，又待了幾秒。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)邵叔是好人。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)這句話他從來沒有對任何人說過。不是因為不確定，而是因為一旦說出口，就會有人問「為什麼」，而那個「為什麼」的答案太長了，也太複雜了，涉及到火災、涉及到父親、涉及到一個十七歲的少年為什麼只有在警察局才能感到一點點安全。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)但他確實是。至少對我來說。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他正準備離開，視線的邊緣捕捉到一個畫面。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "指揮室的門又開了。出來的不是邵叔，是林主任。他穿著那件深灰色的西裝，胸前別著校徽，手裡拿著一個牛皮紙文件夾，腳步很快，朝主道另一頭走去。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他經過指揮室門口的時候，和剛從裡面走出來的邵叔對了一下眼神。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "很短。短到不能稱之為「對視」。更像是兩個人各自發出了一個信號，然後同時收回。林主任的腳步沒有停，邵叔也沒有叫住他。他們什麼都沒有說。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)林主任也去指揮室了？" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)他是校史館的行政主管，安保的事不歸他管吧。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)可能只是工作上的事。校慶期間各部門要協調。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他沒有多想。林主任的身影很快消失在主道盡頭的轉角處，像一滴水落進了河流。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "安檢區那邊的隊伍又長了一些。有人在催前面的人快點，有人在跟保安爭論能不能帶雨傘進去，喧嘩聲在灰色的天空下擴散開來，像一層看不見的霧。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)十一點。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)邵叔說這件事交給他。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)那就交給他吧。" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)至少有一個人是站在我這邊的。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他把手機收回口袋，拉上外套的拉鍊。風又起了，不算大，但帶著雨後的涼意，順著領口往裡鑽。他縮了縮脖子，然後朝教學樓的方向走去。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "腳步聲踩在濕漉漉的柏油路上，很輕，被風聲和遠處的嘈雜蓋過了大半。他走得不快也不慢，一個人，在人群的邊緣，像一滴沿著杯壁滑落的水。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "口袋裡的手機安靜地躺著。螢幕已經熄滅了，但那條訊息還在。「22:22。鐘樓。相機。你欠自己一個真相。」" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "在指揮室裡，邵啟明坐在桌前，面前的對講機安靜了下來。他把剛才顧言給他看的手機畫面在腦子裡又過了一遍。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他的手指無意識地敲了兩下桌面。然後他拿起對講機，按了一個頻道。" },
    { characterId: CharacterId.ShaoQiming, character: "邵叔", dialogue: "鐘樓那邊的監控，調一下。確認今天所有攝像頭都在線。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他說這話的語氣很平，是工作語氣，沒有任何多餘的東西。但他的目光在說這句話的時候，落在了桌面上一張攤開的校園平面圖上——準確地說，落在了鐘樓的位置。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他在那個位置上畫了一個很小的圈，用鉛筆，力道很輕，像是怕紙被戳破。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "門外，風吹動了那面「校慶安保臨時指揮中心」的小旗，啪的一聲，又啪的一聲。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "校園主道上，顧言的背影越來越遠，最終被人群吞沒。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他沒有回頭。" },
];
